class BiometricAuthManager {
    static let shared = BiometricAuthManager()
    
    private let context = LAContext()
    private let userDefaults = UserDefaults.standard
    private let biometricEnabledKey = "BiometricAuthEnabled"
    private let userAuthenticatedKey = "UserAuthenticated"
    
    private init() {}
    
    enum BiometricType {
        case none
        case touchID
        case faceID
    }
    
    var biometricType: BiometricType {
        let context = LAContext()
        var error: NSError?
        
        guard context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error) else {
            return .none
        }
        
        if #available(iOS 11.0, *) {
            switch context.biometryType {
            case .faceID:
                return .faceID
            case .touchID:
                return .touchID
            case .none:
                return .none
            @unknown default:
                return .none
            }
        } else {
            return .touchID
        }
    }
    
    func canUseBiometrics() -> Bool {
        var error: NSError?
        return context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error)
    }
    
    func isBiometricEnabled() -> Bool {
        return userDefaults.bool(forKey: biometricEnabledKey)
    }
    
    func setBiometricEnabled(_ enabled: Bool) {
        userDefaults.set(enabled, forKey: biometricEnabledKey)
    }
    
    func isUserAuthenticated() -> Bool {
        return userDefaults.bool(forKey: userAuthenticatedKey)
    }
    
    func setUserAuthenticated(_ authenticated: Bool) {
        userDefaults.set(authenticated, forKey: userAuthenticatedKey)
    }
    
    func authenticateUser(completion: @escaping (Bool, Error?) -> Void) {
        let context = LAContext()
        var error: NSError?
        
        guard context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error) else {
            completion(false, error)
            return
        }
        
        let reason = biometricType == .faceID ? "Authenticate with Face ID" : "Authenticate with Touch ID"
        
        context.evaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, localizedReason: reason) { success, authError in
            DispatchQueue.main.async {
                if success {
                    self.setUserAuthenticated(true)
                    completion(true, nil)
                } else {
                    completion(false, authError)
                }
            }
        }
    }
    
    func logout() {
        setUserAuthenticated(false)
    }
}

